/**
 * node.js - Node.js-specific implementation for the debug module
 * 
 * This file provides Node.js environment detection and console output formatting
 * for server environments. It's used when debug is running in a Node.js environment
 * and is part of the Express.js dependency tree.
 *
 * Copyright (c) 2014-2017 TJ Holowaychuk <tj@vision-media.ca>
 * MIT License
 */

/**
 * Module dependencies.
 */
var tty = require('tty');
var util = require('util');

/**
 * Import the core debug functionality.
 */
var debug = require('./debug');

/**
 * Reference to the global object (usually `window` or `global`)
 */
var global = (function() { return this; })() || Function('return this')();

/**
 * The currently active debug mode names.
 */
debug.inspectOpts = {};

/**
 * Detect if a terminal supports colors.
 */
function supportsColor(stream) {
  if (process.env.FORCE_COLOR || process.stdout.isTTY) {
    return true;
  }
  
  if (process.platform === 'win32') {
    return true;
  }
  
  if ('CI' in process.env) {
    return ['TRAVIS', 'CIRCLECI', 'APPVEYOR', 'GITLAB_CI', 'GITHUB_ACTIONS'].some(function(sign) {
      return sign in process.env;
    });
  }
  
  if ('TEAMCITY_VERSION' in process.env) {
    return /^(9\.(0*[1-9]\d*)\.|\d{2,}\.)/i.test(process.env.TEAMCITY_VERSION);
  }
  
  if (stream && !stream.isTTY) {
    return false;
  }
  
  if (process.env.COLORTERM === 'truecolor') {
    return true;
  }
  
  if (process.env.TERM === 'dumb') {
    return false;
  }
  
  if (/^screen|^xterm|^vt100|^vt220|^rxvt|color|ansi|cygwin|linux/i.test(process.env.TERM)) {
    return true;
  }
  
  return false;
}

/**
 * Colors for Node.js console.
 */
debug.colors = [
  6, 2, 3, 4, 5, 1 // blue, green, yellow, red, magenta, cyan
];

/**
 * Build up the default `inspectOpts` object from the environment variables.
 */
debug.inspectOpts.colors = supportsColor(process.stderr);

/**
 * Map %o to `util.inspect()` with default options.
 */
debug.formatters.o = function(v) {
  this.inspectOpts.colors = this.useColors;
  return util.inspect(v, this.inspectOpts)
    .replace(/\s*\n\s*/g, ' ');
};

/**
 * Map %O to `util.inspect()` with all options enabled.
 */
debug.formatters.O = function(v) {
  this.inspectOpts.colors = this.useColors;
  return util.inspect(v, this.inspectOpts);
};

/**
 * Detect if colors should be enabled for console output in Node.js.
 *
 * @return {Boolean}
 * @api public
 */
debug.useColors = function() {
  return supportsColor(process.stderr);
};

/**
 * Adds ANSI color escape codes if enabled.
 *
 * @api public
 */
debug.formatArgs = function(args) {
  var name = this.namespace;
  var useColors = this.useColors;

  if (useColors) {
    var c = this.color;
    var colorCode = '\u001b[3' + (c < 8 ? c : '8;5;' + c);
    var prefix = '  ' + colorCode + ';1m' + name + ' ' + '\u001b[0m';

    args[0] = prefix + args[0].split('\n').join('\n' + prefix);
    args.push(colorCode + 'm+' + debug.humanize(this.diff) + '\u001b[0m');
  } else {
    args[0] = getDate() + name + ' ' + args[0];
  }
};

/**
 * Get current timestamp in formatted form.
 */
function getDate() {
  if (debug.inspectOpts.hideDate) {
    return '';
  }
  return new Date().toISOString() + ' ';
}

/**
 * Invokes `util.format()` with the specified arguments and writes to stderr.
 */
debug.log = function() {
  return process.stderr.write(util.format.apply(util, arguments) + '\n');
};

/**
 * Save `namespaces`.
 *
 * @param {String} namespaces
 * @api private
 */
debug.save = function(namespaces) {
  if (namespaces) {
    process.env.DEBUG = namespaces;
  } else {
    // If you set a process.env field to null or undefined, it gets cast to the
    // string 'null' or 'undefined'. Just delete instead.
    delete process.env.DEBUG;
  }
};

/**
 * Load `namespaces`.
 *
 * @return {String} returns the previously persisted debug modes
 * @api private
 */
debug.load = function() {
  return process.env.DEBUG;
};

/**
 * Init logic for `debug` instances.
 *
 * Create a new `inspectOpts` object in case `useColors` is set
 * differently for a particular `debug` instance.
 */
debug.init = function(debug) {
  debug.inspectOpts = {};

  var keys = Object.keys(debug.inspectOpts);
  for (var i = 0; i < keys.length; i++) {
    debug.inspectOpts[keys[i]] = debug.inspectOpts[keys[i]];
  }
};

/**
 * Enable namespaces listed in `process.env.DEBUG` initially.
 */
debug.enable(debug.load());

/**
 * Export the debug module.
 */
module.exports = debug;